SELECT , c.name as category_name, u.nickname as author_name FROM article a LEFT JOIN category c ON a.category_id = c.id LEFT JOIN `user` u ON a.user_id = u.id WHERE a.status = 1
AND a.category_id = #{categoryId}
AND (a.title LIKE CONCAT('%', #{keyword}, '%') OR a.summary LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY a.create_time DESC LIMIT #{offset}, #{limit}

SELECT COUNT(*) FROM article WHERE status = 1
AND category_id = #{categoryId}
AND (title LIKE CONCAT('%', #{keyword}, '%') OR summary LIKE CONCAT('%', #{keyword}, '%'))
